implementation:
// 统计数据集总行数
long totalRows = csvData.getRecords().size();
return totalRows;

// 根据表头获取列数
int columnCount = csvData.getHeader().size();
return columnCount;

// 计算某列的基本统计量
ColumnStat stat = new ColumnStat(columnName, count, mean, median, stdDev, min, max, missingCount, outlierCount);
return stat;

// 移除含空值的行
List<Record> cleaned = records.stream()
    .filter(r -> columns.stream().noneMatch(col -> r.get(col) == null))
    .toList();
return cleaned;

// 基于 IQR 移除异常值
double q1 = percentile(data, 25);
double q3 = percentile(data, 75);
double iqr = q3 - q1;
double lower = q1 - multiplier * iqr;
double upper = q3 + multiplier * iqr;
return data.stream().filter(v -> v >= lower && v <= upper).toList();

// 填充缺失值
double fillValue = switch(fillMethod) {
    case "MEAN" -> calculateMean(column);
    case "MEDIAN" -> calculateMedian(column);
    case "MODE" -> calculateMode(column);
    case "CONSTANT" -> Double.parseDouble(constantValue);
    default -> 0;
};
return fillMissingWith(column, fillValue);

// Min-Max 归一化
double colMin = columnStats.get(columnName).min();
double colMax = columnStats.get(columnName).max();
double range = colMax - colMin;
return data.stream()
    .map(v -> minRange + (v - colMin) / range * (maxRange - minRange))
    .toList();

// Z-Score 标准化
double mean = columnStats.get(columnName).mean();
double stdDev = columnStats.get(columnName).stdDev();
return data.stream()
    .map(v -> (v - mean) / stdDev)
    .toList();

// 等宽/等频分箱
double colMin = columnStats.get(columnName).min();
double colMax = columnStats.get(columnName).max();
return createBins(data, colMin, colMax, binCount, method);

// 皮尔逊相关系数
double meanX = columnStats.get(columnX).mean();
double meanY = columnStats.get(columnY).mean();
double covariance = 0, stdX = 0, stdY = 0;
for (int i = 0; i < n; i++) {
    double dx = get(colX, i) - meanX;
    double dy = get(colY, i) - meanY;
    covariance += dx * dy;
    stdX += dx * dx;
    stdY += dy * dy;
}
return covariance / Math.sqrt(stdX * stdY);

// 分组聚合
Map<String, Double> result = new HashMap<>();
for (Record r : records) {
    String key = r.get(groupColumn);
    double val = r.get(aggColumn);
    result.merge(key, val, Double::sum);
}
return result;

// 百分位数计算
List<Double> sorted = data.stream().sorted().toList();
double k = (sorted.size() - 1) * percentileValue / 100.0;
int f = (int) Math.floor(k);
int c = (int) Math.ceil(k);
return (f == c) ? sorted.get(f) : sorted.get(f) * (c - k) + sorted.get(c) * (k - f);
